var ANNOTATION_IDS = ["tut-ann-0", "tut-ann-1", "tut-ann-2", "tut-ann-3", "tut-ann-4", "tut-ann-5", "tut-ann-6", "tut-ann-7", "tut-ann-8", "tut-ann-9", "tut-ann-10", "tut-ann-11", "tut-ann-12", "tut-ann-13"];
var PANEL_IDS      = ["tut-panel-0", "tut-panel-1", "tut-panel-2", "tut-panel-3", "tut-panel-4", "tut-panel-5", "tut-panel-6", "tut-panel-7", "tut-panel-8", "tut-panel-9", "tut-panel-10", "tut-panel-11", "tut-panel-12", "tut-panel-13"];

var currentStep = -1;

// ---- inlet handlers ----

function bang() {
    gotoStep(0);
}

function msg_int(step) {
    gotoStep(step);
}

function prev() {
    gotoStep(Math.max(0, currentStep - 1));
}

function next() {
    gotoStep(Math.min(STEPS.length - 1, currentStep + 1));
}

// ---- core ----

function gotoStep(step) {
    if (step < 0 || step >= STEPS.length) return;

    var p = this.patcher;

    // Hide all panels and annotation comments
    for (var i = 0; i < PANEL_IDS.length; i++) {
        var obj = p.getnamed(PANEL_IDS[i]);
        if (obj) obj.hidden = 1;
    }
    for (var i = 0; i < ANNOTATION_IDS.length; i++) {
        var obj = p.getnamed(ANNOTATION_IDS[i]);
        if (obj) obj.hidden = 1;
    }

    currentStep = step;

    // Show this step's panel and annotation
    var panel = p.getnamed(PANEL_IDS[step]);
    if (panel) panel.hidden = 0;

    var ann = p.getnamed(ANNOTATION_IDS[step]);
    if (ann) ann.hidden = 0;

    post("Tutorial step " + step + ": " + STEPS[step].name + "\n");
}
